#!/usr/bin/env python3\n\"\"\"\n探索 RAG 知识库的存储结构\n显示文件在磁盘上的实际位置\n\"\"\"\nimport os\nimport json\nfrom pathlib import Path\nimport pickle\n\ndef print_tree(directory, prefix=\"\", max_depth=4, current_depth=0):\n    \"\"\"递归打印目录树\"\"\"\n    if current_depth >= max_depth:\n        return\n    \n    try:\n        entries = sorted(os.listdir(directory))\n    except PermissionError:\n        return\n    \n    dirs = [e for e in entries if os.path.isdir(os.path.join(directory, e))]\n    files = [e for e in entries if os.path.isfile(os.path.join(directory, e))]\n    \n    # 打印文件\n    for i, file in enumerate(files):\n        is_last = (i == len(files) - 1) and len(dirs) == 0\n        print(f\"{prefix}{'└── ' if is_last else '├── '}📄 {file}\")\n    \n    # 打印目录\n    for i, dir_name in enumerate(dirs):\n        is_last = i == len(dirs) - 1\n        print(f\"{prefix}{'└── ' if is_last else '├── '}📁 {dir_name}/\")\n        \n        new_prefix = prefix + (\"    \" if is_last else \"│   \")\n        print_tree(os.path.join(directory, dir_name), new_prefix, max_depth, current_depth + 1)\n\ndef explore_storage():\n    \"\"\"探索存储结构\"\"\"\n    print(\"\\n\" + \"=\"*70)\n    print(\"RAG 知识库存储结构探索\")\n    print(\"=\"*70)\n    \n    # 检查 data 目录\n    data_dir = Path(\"./data\")\n    if not data_dir.exists():\n        print(\"\\n⚠️  ./data 目录不存在\")\n        print(\"提示：运行 python -m rag_knowledge_base.main 后会自动创建\")\n        return\n    \n    print(\"\\n📂 完整的目录结构：\\n\")\n    print_tree(str(data_dir))\n    \n    # 分析 storage 目录\n    storage_dir = data_dir / \"storage\"\n    if storage_dir.exists():\n        print(\"\\n\" + \"=\"*70)\n        print(\"📊 向量数据库信息 (persist_path)\")\n        print(\"=\"*70)\n        \n        vector_store = storage_dir / \"vector_store\"\n        if vector_store.exists():\n            print(f\"\\n✓ 向量数据库位置: {vector_store}\")\n            print(f\"  - 大小: {sum(f.stat().st_size for f in vector_store.rglob('*') if f.is_file()) / 1024:.2f} KB\")\n            print(f\"  - 文件数: {len(list(vector_store.rglob('*')))}\")\n        \n        doc_mapping = storage_dir / \"doc_mapping.pkl\"\n        if doc_mapping.exists():\n            print(f\"\\n✓ 文档映射文件: {doc_mapping}\")\n            try:\n                with open(doc_mapping, 'rb') as f:\n                    mappings = pickle.load(f)\n                print(f\"  - 记录的文档数: {len(mappings)}\")\n                print(f\"  - 文件大小: {doc_mapping.stat().st_size} 字节\")\n                \n                if mappings:\n                    print(\"\\n  📋 文档映射内容示例：\")\n                    for i, (md5, info) in enumerate(list(mappings.items())[:2]):\n                        print(f\"\\n    文档 {i+1}:\")\n                        print(f\"      MD5: {md5}\")\n                        print(f\"      原始路径: {info.get('original_path', 'N/A')}\")\n                        print(f\"      处理路径: {info.get('processed_path', 'N/A')}\")\n                        print(f\"      分块数: {info.get('parts_count', 'N/A')}\")\n            except Exception as e:\n                print(f\"  ⚠️  无法读取映射文件: {e}\")\n    \n    # 分析 documents 目录\n    docs_dir = data_dir / \"documents\"\n    if docs_dir.exists():\n        print(\"\\n\" + \"=\"*70)\n        print(\"📚 文档管理信息 (DataLoader)\")\n        print(\"=\"*70)\n        \n        # 原始文件\n        original_dir = docs_dir / \"original_files\"\n        if original_dir.exists():\n            print(f\"\\n✓ 原始文件存储: {original_dir}\")\n            for ext_dir in original_dir.iterdir():\n                if ext_dir.is_dir():\n                    files = list(ext_dir.glob('*'))\n                    if files:\n                        total_size = sum(f.stat().st_size for f in files)\n                        print(f\"  - .{ext_dir.name}: {len(files)} 个文件, {total_size / 1024:.2f} KB\")\n        \n        # 处理后的文件\n        processed_dir = docs_dir / \"processed_documents\"\n        if processed_dir.exists():\n            print(f\"\\n✓ 处理后的文件: {processed_dir}\")\n            json_files = list(processed_dir.glob('*.json'))\n            if json_files:\n                print(f\"  - JSON 文件数: {len(json_files)}\")\n                total_size = sum(f.stat().st_size for f in json_files)\n                print(f\"  - 总大小: {total_size / 1024:.2f} KB\")\n                \n                # 显示第一个文件的内容\n                if json_files:\n                    print(f\"\\n  📄 处理后文件示例 ({json_files[0].name}):\")\n                    try:\n                        with open(json_files[0], 'r', encoding='utf-8') as f:\n                            data = json.load(f)\n                        print(f\"      - 原始路径: {data.get('original_path', 'N/A')}\")\n                        print(f\"      - 文档块数: {data.get('document_count', 'N/A')}\")\n                        print(f\"      - MD5: {data.get('file_md5', 'N/A')}\")\n                        if data.get('documents'):\n                            print(f\"      - 第一块内容: {data['documents'][0]['content'][:100]}...\")\n                    except Exception as e:\n                        print(f\"      ⚠️  无法读取: {e}\")\n        \n        # 元数据\n        metadata_file = docs_dir / \"file_metadata.json\"\n        if metadata_file.exists():\n            print(f\"\\n✓ 文件元数据: {metadata_file}\")\n            try:\n                with open(metadata_file, 'r', encoding='utf-8') as f:\n                    metadata = json.load(f)\n                print(f\"  - 记录的文件数: {len(metadata)}\")\n                print(f\"  - 文件大小: {metadata_file.stat().st_size} 字节\")\n                \n                if metadata:\n                    print(\"\\n  📋 元数据示例：\")\n                    for i, (md5, info) in enumerate(list(metadata.items())[:1]):\n                        print(f\"\\n    文件 {i+1}:\")\n                        print(f\"      MD5: {md5}\")\n                        print(f\"      存储名: {info.get('stored_name', 'N/A')}\")\n                        print(f\"      文件大小: {info.get('file_size', 'N/A')} 字节\")\n                        print(f\"      文件类型: {info.get('file_extension', 'N/A')}\")\n                        print(f\"      添加时间: {info.get('added_timestamp', 'N/A')}\")\n            except Exception as e:\n                print(f\"  ⚠️  无法读取: {e}\")\n    \n    print(\"\\n\" + \"=\"*70)\n    print(\"💡 存储结构说明\")\n    print(\"=\"*70)\n    print(\"\"\"\n1. persist_path=\"./data/storage\" 中存储：\n   - vector_store/: Qdrant 向量数据库（最重要！）\n   - doc_mapping.pkl: 文档映射信息\n\n2. DataLoader 在 \"./data/documents\" 中存储：\n   - original_files/: 原始文件备份\n   - processed_documents/: 处理后的 JSON 文件\n   - file_metadata.json: 文件元数据索引\n\n3. 数据流：\n   用户文件 → original_files → processed_documents → vector_store\n\n4. 重要提示：\n   - 删除 vector_store 会丢失所有向量数据\n   - 删除 original_files 不影响查询（但失去备份）\n   - 删除 processed_documents 不影响查询（但需要重新处理）\n    \"\"\")\n\nif __name__ == \"__main__\":\n    explore_storage()\n
